        Scanner sc = new Scanner(System.in);
        String s = sc.nextLine(), p = sc.nextLine();
        if(s.length() < p.length()) return;
        int[] pc = new int[26], sc_arr = new int[26];
        for(char c : p.toCharArray()) pc[c-'a']++;
        for(int i=0; i<p.length(); i++) sc_arr[s.charAt(i)-'a']++;
        if(Arrays.equals(pc, sc_arr)) System.out.print("0 ");
        for(int i=1; i <= s.length()-p.length(); i++) {
            sc_arr[s.charAt(i-1)-'a']--;
            sc_arr[s.charAt(i+p.length()-1)-'a']++;
            if(Arrays.equals(pc, sc_arr)) System.out.print(i + " ");
        }
    }
}

